code = """import json
# load list of businesses that accept credit cards
accept_call = var_call_fC40ymA3nKMGxxAB5LmNhIuh
accept_data = json.loads(accept_call)
accept_refs = set(accept_data['business_refs'])

# load reviews
rev_fp = var_call_y3j5OQbjV2NqkG8hN94O7LQu
with open(rev_fp,'r') as f:
    reviews = json.load(f)

# filter reviews for businesses that accept credit cards
filtered = [r for r in reviews if r.get('business_ref') in accept_refs]
# compute average rating per business
from collections import defaultdict
scores = defaultdict(list)
for r in filtered:
    try:
        scores[r['business_ref']].append(float(r['rating']))
    except:
        pass

avg_per_biz = {biz: sum(vals)/len(vals) for biz, vals in scores.items()}

# load biz to categories mapping from biz_to_cats in accept_data
biz_to_cats = accept_data['biz_to_cats']

# build category to list of business refs
cat_map = defaultdict(list)
for biz, cats in biz_to_cats.items():
    if not cats:
        cat_map['Unknown'].append(biz)
    else:
        for c in cats:
            cat_map[c].append(biz)

# compute counts of businesses that accept credit cards per category
cat_counts = {c: len(set(biz_list)) for c, biz_list in cat_map.items()}
# compute average rating per category (average of business averages among businesses in that category and that have reviews)
cat_avg_rating = {}
for c, biz_list in cat_map.items():
    vals = []
    for b in set(biz_list):
        if b in avg_per_biz:
            vals.append(avg_per_biz[b])
    if vals:
        cat_avg_rating[c] = sum(vals)/len(vals)
    else:
        cat_avg_rating[c] = None

# find category with largest number of biz
top_cat = max(cat_counts.items(), key=lambda x: x[1])[0]
result = {'top_category': top_cat, 'business_count': cat_counts[top_cat], 'average_rating': cat_avg_rating.get(top_cat)}

print('__RESULT__:')
print(json.dumps(result))"""

